// ---- LOAD DATABASE CONNECTION ----
require_once 'db_connect1.php';

// ---- SESSION & HELPERS ----
session_start();
function sanitize($d) { return htmlspecialchars(strip_tags(trim($d))); }
function isLoggedIn() { return isset($_SESSION['user_id']); }
function isAdmin() { return isset($_SESSION['role']) && $_SESSION['role'] === 'admin'; }
function redirect($url) { header("Location: $url"); exit; }

$action = $_POST['action'] ?? $_GET['action'] ?? '';
$message = ''; $messageType = '';

// ---- REGISTER ----
if ($action === 'register') {
    $db = getDB();
    $name = sanitize($_POST['name'] ?? ''); $email = sanitize($_POST['email'] ?? '');
    $phone = sanitize($_POST['phone'] ?? ''); $pass = $_POST['password'] ?? '';
    $cpass = $_POST['confirm_password'] ?? '';
    if (!$name || !$email || !$pass) { $message='All fields required.'; $messageType='error'; }
    elseif ($pass !== $cpass) { $message='Passwords do not match.'; $messageType='error'; }
    elseif (strlen($pass) < 6) { $message='Min 6 characters.'; $messageType='error'; }
    elseif ($db) {
        $stmt = $db->prepare("SELECT id FROM users WHERE email=?");
        $stmt->bind_param("s", $email); $stmt->execute(); $stmt->store_result();
        if ($stmt->num_rows > 0) { $message='Email already registered.'; $messageType='error'; }
        else {
            $hashed = password_hash($pass, PASSWORD_DEFAULT);
            $stmt2 = $db->prepare("INSERT INTO users (name, email, phone, password) VALUES (?,?,?,?)");
            $stmt2->bind_param("ssss", $name, $email, $phone, $hashed);
            if ($stmt2->execute()) { $message='Registration successful! Please login.'; $messageType='success'; }
            else { $message='Registration failed.'; $messageType='error'; }
        }
    } else { $message='Demo mode: Registration simulated!'; $messageType='success'; }
}

// ---- LOGIN ----
if ($action === 'login') {
    $db = getDB(); $email = sanitize($_POST['email'] ?? '');
    $pass = $_POST['password'] ?? ''; $loginType = $_POST['login_type'] ?? 'user';
    if ($db) {
        $stmt = $db->prepare("SELECT id, name, email, password, role FROM users WHERE email=?");
        $stmt->bind_param("s", $email); $stmt->execute();
        $result = $stmt->get_result(); $user = $result->fetch_assoc();
        if ($user && password_verify($pass, $user['password'])) {
            if ($loginType === 'admin' && $user['role'] !== 'admin') {
                $message='Access denied. Not an admin.'; $messageType='error';
            } else {
                $_SESSION['user_id'] = $user['id']; $_SESSION['user_name'] = $user['name'];
                $_SESSION['user_email'] = $user['email']; $_SESSION['role'] = $user['role'];
                redirect('?page=' . ($user['role'] === 'admin' ? 'admin_dashboard' : 'dashboard'));
            }
        } else { $message='Invalid email or password.'; $messageType='error'; }
    } else {
        if ($email === 'admin@vrindavan.com' && $pass === 'Admin@123') {
            $_SESSION['user_id'] = 1; $_SESSION['user_name'] = 'Studio Admin';
            $_SESSION['user_email'] = $email; $_SESSION['role'] = 'admin';
            redirect('?page=admin_dashboard');
        } elseif ($email && $pass) {
            $_SESSION['user_id'] = 2; $_SESSION['user_name'] = 'Demo User';
            $_SESSION['user_email'] = $email; $_SESSION['role'] = 'user';
            redirect('?page=dashboard');
        } else { $message='Invalid credentials.'; $messageType='error'; }
    }
}

// ---- LOGOUT ----
if ($action === 'logout' || ($_GET['action'] ?? '') === 'logout') { session_destroy(); redirect('?page=home'); }

// ---- BOOK APPOINTMENT ----
if ($action === 'book_appointment') {
    if (!isLoggedIn()) {
        $message='⚠️ You are not registered! Please create an account or login to book an appointment.'; $messageType='error';
        $page = 'book';
    } else {
    $db = getDB();
    $name = sanitize($_POST['b_name'] ?? ''); $email = sanitize($_POST['b_email'] ?? '');
    $phone = sanitize($_POST['b_phone'] ?? ''); $service = sanitize($_POST['b_service'] ?? '');
    $date = sanitize($_POST['b_date'] ?? ''); $time = sanitize($_POST['b_time'] ?? '');
    $msg = sanitize($_POST['b_message'] ?? ''); $uid = $_SESSION['user_id'] ?? null;
    if (!$name || !$email || !$phone || !$service || !$date || !$time) {
        $message='All booking fields required.'; $messageType='error';
    } elseif ($db) {
        $stmt = $db->prepare("INSERT INTO bookings (user_id, name, email, phone, service, date, time_slot, message) VALUES (?,?,?,?,?,?,?,?)");
        $stmt->bind_param("isssssss", $uid, $name, $email, $phone, $service, $date, $time, $msg);
        if ($stmt->execute()) { $message='✨ Appointment booked! We will confirm shortly.'; $messageType='success'; }
        else { $message='Booking failed. Try again.'; $messageType='error'; }
    } else { $message='✨ Demo: Appointment for '.$name.' on '.$date.' booked!'; $messageType='success'; }
    } // end isLoggedIn check
}

// ---- UPDATE BOOKING STATUS (Admin) ----
if ($action === 'update_booking' && isAdmin()) {
    $db = getDB(); $bid = (int)($_POST['booking_id'] ?? 0);
    $status = sanitize($_POST['status'] ?? '');
    if ($db && $bid && in_array($status, ['confirmed','cancelled','pending'])) {
        $stmt = $db->prepare("UPDATE bookings SET status=? WHERE id=?");
        $stmt->bind_param("si", $status, $bid); $stmt->execute();
        $message='Booking updated.'; $messageType='success';
    }
}


