<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>Vrindavan Glam Studio</title>
<link href="https://fonts.googleapis.com/css2?family=Cinzel+Decorative:wght@400;700;900&family=Cormorant+Garamond:ital,wght@0,300;0,400;0,600;1,400&family=Raleway:wght@300;400;500;600&display=swap" rel="stylesheet">
<link rel="stylesheet" href="https://cdnjs.cloudflare.com/ajax/libs/font-awesome/6.4.0/css/all.min.css">
<style>
:root {
    --black:#050505; --dark:#0a0a0a; --card:#111111; --card2:#161616;
    --gold:#D4AF37; --gold-light:#F0D060; --gold-dark:#9A7B20;
    --green:#2ECC71; --green-dark:#1a7a42; --peacock:#005F73;
    --peacock-mid:#0A9396; --peacock-light:#94D2BD;
    --white:#F5F5F0; --gray:#888; --border:rgba(212,175,55,0.25);
}
*,*::before,*::after{box-sizing:border-box;margin:0;padding:0;}
html{scroll-behavior:smooth;}
body{background:var(--black);color:var(--white);font-family:'Raleway',sans-serif;min-height:100vh;overflow-x:hidden;}
::-webkit-scrollbar{width:6px;}
::-webkit-scrollbar-track{background:var(--dark);}
::-webkit-scrollbar-thumb{background:var(--gold-dark);border-radius:3px;}
#particles-canvas{position:fixed;top:0;left:0;width:100%;height:100%;z-index:0;pointer-events:none;}

/* NAV */
nav{position:fixed;top:0;left:0;right:0;z-index:1000;display:flex;align-items:center;justify-content:space-between;padding:18px 5%;background:rgba(5,5,5,0.92);backdrop-filter:blur(20px);border-bottom:1px solid var(--border);transition:all 0.3s;}
.nav-logo{text-decoration:none;display:flex;align-items:center;gap:10px;}
.nav-logo img{height:52px;width:auto;object-fit:contain;filter:drop-shadow(0 0 8px rgba(212,175,55,0.5));transition:filter 0.3s;cursor:zoom-in;}
.nav-logo img:hover{filter:drop-shadow(0 0 14px rgba(212,175,55,0.8));}
.nav-links{display:flex;align-items:center;gap:25px;list-style:none;}
.nav-links a{color:var(--white);text-decoration:none;font-size:0.82rem;letter-spacing:1.5px;text-transform:uppercase;font-weight:500;transition:color 0.3s;position:relative;}
.nav-links a::after{content:'';position:absolute;bottom:-4px;left:0;width:0;height:1px;background:var(--gold);transition:width 0.3s;}
.nav-links a:hover{color:var(--gold);}
.nav-links a:hover::after{width:100%;}
.nav-btn{background:linear-gradient(135deg,var(--gold-dark),var(--gold));color:var(--black)!important;padding:8px 22px;border-radius:30px;font-weight:600;font-size:0.8rem!important;letter-spacing:1px;}
.nav-btn:hover{transform:translateY(-2px);box-shadow:0 8px 25px rgba(212,175,55,0.4);color:var(--black)!important;}
.nav-btn::after{display:none!important;}
.nav-user{display:flex;align-items:center;gap:15px;}
.nav-user span{color:var(--gold);font-size:0.82rem;}
.admin-badge{background:linear-gradient(135deg,var(--gold-dark),var(--gold));color:var(--black);padding:3px 10px;border-radius:20px;font-size:0.7rem;font-weight:700;letter-spacing:1px;}

/* PAGE */
.page-wrapper{position:relative;z-index:1;padding-top:80px;}

/* HERO */
.hero{min-height:100vh;display:flex;align-items:center;justify-content:center;text-align:center;position:relative;overflow:hidden;padding:80px 5% 60px;}
.hero-bg{position:absolute;inset:0;background:radial-gradient(ellipse 80% 60% at 50% 40%,rgba(0,95,115,0.2) 0%,transparent 60%),radial-gradient(ellipse 60% 40% at 20% 80%,rgba(212,175,55,0.08) 0%,transparent 50%);z-index:0;}
.hero-mandala{position:absolute;width:700px;height:700px;top:50%;left:50%;transform:translate(-50%,-50%);opacity:0.04;border:1px solid var(--gold);border-radius:50%;animation:rotateMandala 30s linear infinite;}
.hero-mandala::before,.hero-mandala::after{content:'';position:absolute;inset:20px;border-radius:50%;border:1px solid var(--gold);}
.hero-mandala::after{inset:60px;}
@keyframes rotateMandala{from{transform:translate(-50%,-50%) rotate(0deg);}to{transform:translate(-50%,-50%) rotate(360deg);}}
.hero-content{position:relative;z-index:2;max-width:900px;}
.hero-tag{display:inline-block;font-size:0.75rem;letter-spacing:4px;text-transform:uppercase;color:var(--peacock-light);border:1px solid var(--peacock);padding:6px 20px;border-radius:30px;margin-bottom:30px;animation:fadeInDown 1s ease forwards;opacity:0;}
.hero h1{font-family:'Cinzel Decorative',serif;font-size:clamp(2.5rem,7vw,5.5rem);font-weight:900;color:var(--gold);line-height:1.1;margin-bottom:20px;text-shadow:0 0 60px rgba(212,175,55,0.3);animation:fadeInUp 1s ease 0.2s forwards;opacity:0;}
.hero h1 em{font-style:italic;color:var(--gold-light);font-family:'Cormorant Garamond',serif;font-size:1.2em;}
.hero-sub{font-family:'Cormorant Garamond',serif;font-size:1.4rem;font-style:italic;color:var(--peacock-light);margin-bottom:15px;animation:fadeInUp 1s ease 0.4s forwards;opacity:0;}
.hero p{font-size:1rem;color:rgba(245,245,240,0.65);max-width:560px;margin:0 auto 40px;line-height:1.8;animation:fadeInUp 1s ease 0.6s forwards;opacity:0;}
.hero-btns{display:flex;gap:20px;justify-content:center;flex-wrap:wrap;animation:fadeInUp 1s ease 0.8s forwards;opacity:0;}
.btn-primary{background:linear-gradient(135deg,var(--gold-dark),var(--gold),var(--gold-light));color:var(--black);padding:14px 40px;border-radius:50px;font-weight:700;font-size:0.9rem;letter-spacing:2px;text-transform:uppercase;text-decoration:none;border:none;cursor:pointer;transition:all 0.3s;box-shadow:0 8px 30px rgba(212,175,55,0.35);display:inline-flex;align-items:center;gap:8px;}
.btn-primary:hover{transform:translateY(-3px);box-shadow:0 15px 40px rgba(212,175,55,0.5);}
.btn-secondary{background:transparent;color:var(--peacock-light);padding:14px 40px;border-radius:50px;font-weight:600;font-size:0.9rem;letter-spacing:2px;text-transform:uppercase;text-decoration:none;border:1px solid var(--peacock);cursor:pointer;transition:all 0.3s;display:inline-flex;align-items:center;gap:8px;}
.btn-secondary:hover{background:rgba(0,95,115,0.2);transform:translateY(-3px);border-color:var(--peacock-light);}

@keyframes fadeInDown{from{opacity:0;transform:translateY(-20px);}to{opacity:1;transform:translateY(0);}}
@keyframes fadeInUp{from{opacity:0;transform:translateY(30px);}to{opacity:1;transform:translateY(0);}}

/* SECTIONS */
.section{padding:100px 5%;position:relative;z-index:1;}
.section-header{text-align:center;margin-bottom:60px;}
.section-tag{display:inline-block;font-size:0.7rem;letter-spacing:5px;text-transform:uppercase;color:var(--green);margin-bottom:15px;}
.section-title{font-family:'Cinzel Decorative',serif;font-size:clamp(1.8rem,4vw,3rem);color:var(--gold);margin-bottom:15px;line-height:1.2;}
.section-subtitle{font-family:'Cormorant Garamond',serif;font-size:1.2rem;font-style:italic;color:var(--peacock-light);max-width:500px;margin:0 auto;}
.section-divider{width:80px;height:2px;background:linear-gradient(90deg,transparent,var(--gold),transparent);margin:20px auto 0;}
.shimmer-text{background:linear-gradient(90deg,var(--gold) 0%,var(--gold-light) 40%,var(--gold) 60%,var(--gold-light) 100%);background-size:200%;-webkit-background-clip:text;-webkit-text-fill-color:transparent;animation:shimmer 3s linear infinite;}
@keyframes shimmer{to{background-position:200% center;}}
.scroll-reveal{opacity:0;transform:translateY(30px);transition:all 0.7s ease;}
.scroll-reveal.revealed{opacity:1;transform:none;}

/* SERVICES */
.services-grid{display:grid;grid-template-columns:repeat(auto-fit,minmax(280px,1fr));gap:25px;max-width:1200px;margin:0 auto;}
.service-card{background:var(--card);border:1px solid var(--border);border-radius:16px;overflow:hidden;transition:all 0.4s;cursor:pointer;position:relative;}
.service-card::before{content:'';position:absolute;top:0;left:0;right:0;height:2px;background:linear-gradient(90deg,var(--peacock),var(--gold),var(--green));transform:scaleX(0);transition:transform 0.4s;z-index:2;}
.service-card:hover{transform:translateY(-8px);border-color:rgba(212,175,55,0.5);box-shadow:0 20px 60px rgba(0,95,115,0.2);}
.service-card:hover::before{transform:scaleX(1);}
.service-img-wrap{width:100%;height:200px;overflow:hidden;position:relative;}
.service-img-wrap img{width:100%;height:100%;object-fit:cover;transition:transform 0.5s;}
.service-card:hover .service-img-wrap img{transform:scale(1.08);}
.service-img-overlay{position:absolute;inset:0;background:linear-gradient(to top,rgba(5,5,5,0.9) 0%,transparent 60%);}
.service-body{padding:25px;}
.service-icon{font-size:1.5rem;margin-bottom:10px;display:inline-block;}
.service-card h3{font-family:'Cinzel Decorative',serif;font-size:0.95rem;color:var(--gold);margin-bottom:10px;letter-spacing:1px;}
.service-card p{font-size:0.85rem;color:rgba(245,245,240,0.6);line-height:1.6;margin-bottom:12px;}
.service-price{display:inline-block;color:var(--green);font-weight:700;font-size:0.95rem;background:rgba(46,204,113,0.1);padding:4px 14px;border-radius:20px;border:1px solid rgba(46,204,113,0.3);}
.service-learn{display:inline-block;color:var(--peacock-light);font-size:0.78rem;letter-spacing:1px;text-decoration:none;margin-left:10px;text-transform:uppercase;transition:color 0.3s;}
.service-learn:hover{color:var(--gold);}

/* SERVICE MODAL */
.modal-overlay{position:fixed;inset:0;background:rgba(0,0,0,0.85);z-index:9000;display:none;align-items:center;justify-content:center;padding:20px;backdrop-filter:blur(4px);}
.modal-overlay.active{display:flex;}
.modal-box{background:var(--card);border:1px solid var(--border);border-radius:20px;max-width:700px;width:100%;max-height:90vh;overflow-y:auto;position:relative;animation:modalIn 0.3s ease;}
@keyframes modalIn{from{opacity:0;transform:scale(0.95);}to{opacity:1;transform:scale(1);}}
.modal-img{width:100%;height:280px;object-fit:cover;border-radius:20px 20px 0 0;}
.modal-content{padding:35px;}
.modal-icon{font-size:2rem;margin-bottom:10px;}
.modal-title{font-family:'Cinzel Decorative',serif;font-size:1.5rem;color:var(--gold);margin-bottom:8px;}
.modal-price{color:var(--green);font-size:1.1rem;font-weight:700;margin-bottom:15px;}
.modal-desc{color:rgba(245,245,240,0.75);line-height:1.8;margin-bottom:25px;}
.modal-close{position:absolute;top:15px;right:15px;width:36px;height:36px;border-radius:50%;background:rgba(255,255,255,0.1);border:none;color:var(--white);cursor:pointer;font-size:1.1rem;display:flex;align-items:center;justify-content:center;transition:all 0.2s;}
.modal-close:hover{background:rgba(212,175,55,0.3);color:var(--gold);}

/* GALLERY */
.gallery-tabs{display:flex;gap:10px;justify-content:center;margin-bottom:40px;flex-wrap:wrap;}
.gallery-tab{background:none;border:1px solid var(--border);color:var(--gray);padding:10px 30px;border-radius:30px;font-family:'Raleway',sans-serif;font-size:0.85rem;letter-spacing:2px;text-transform:uppercase;cursor:pointer;transition:all 0.3s;}
.gallery-tab.active,.gallery-tab:hover{background:linear-gradient(135deg,var(--peacock),var(--peacock-mid));border-color:var(--peacock);color:var(--white);}
.gallery-grid{display:grid;grid-template-columns:repeat(4,1fr);gap:12px;max-width:1200px;margin:0 auto;}
.gallery-item{position:relative;border-radius:12px;overflow:hidden;aspect-ratio:1;cursor:pointer;}
.gallery-item img{width:100%;height:100%;object-fit:cover;transition:transform 0.5s;}
.gallery-item:hover img{transform:scale(1.1);}
.gallery-overlay{position:absolute;inset:0;background:rgba(0,0,0,0);transition:background 0.3s;display:flex;align-items:center;justify-content:center;}
.gallery-item:hover .gallery-overlay{background:rgba(0,95,115,0.4);}
.gallery-icon{color:white;font-size:2rem;opacity:0;transform:scale(0.5);transition:all 0.3s;}
.gallery-item:hover .gallery-icon{opacity:1;transform:scale(1);}
.gallery-panel{display:none;}
.gallery-panel.active{display:block;}

/* ABOUT */
.about-section{display:grid;grid-template-columns:1fr 1.5fr;gap:60px;max-width:1100px;margin:0 auto;align-items:center;}
.about-visual{position:relative;height:350px;}
.about-circle{position:absolute;border-radius:50%;border:1px solid var(--border);}
.about-circle-1{width:100%;height:100%;top:0;left:0;background:radial-gradient(circle at 40% 40%,rgba(0,95,115,0.2),rgba(212,175,55,0.05));animation:rotateMandala 20s linear infinite;}
.about-circle-2{width:70%;height:70%;top:15%;left:15%;background:radial-gradient(circle at 60% 60%,rgba(212,175,55,0.1),transparent);animation:rotateMandala 15s linear infinite reverse;}
.about-center{position:absolute;inset:0;display:flex;flex-direction:column;align-items:center;justify-content:center;text-align:center;padding:10px;overflow:hidden;}
.big-num{font-family:'Cinzel Decorative',serif;font-size:4rem;font-weight:900;color:var(--gold);line-height:1;}
.about-text h3{font-family:'Cinzel Decorative',serif;font-size:1.5rem;color:var(--gold);margin-bottom:20px;}
.about-text p{color:rgba(245,245,240,0.7);line-height:1.8;margin-bottom:15px;font-size:0.95rem;}
.about-features{display:flex;flex-direction:column;gap:10px;margin-top:20px;}
.about-feature{display:flex;align-items:center;gap:10px;font-size:0.88rem;color:var(--peacock-light);}
.about-feature i{color:var(--gold);}

/* BOOKING */
.booking-wrapper{max-width:800px;margin:0 auto;background:var(--card);border:1px solid var(--border);border-radius:20px;padding:50px;position:relative;overflow:hidden;}
.form-grid{display:grid;grid-template-columns:1fr 1fr;gap:20px;}
.form-group{display:flex;flex-direction:column;gap:8px;}
.form-group.full{grid-column:1/-1;}
.form-group label{font-size:0.78rem;letter-spacing:2px;text-transform:uppercase;color:var(--gold-dark);font-weight:600;}
.form-group input,.form-group select,.form-group textarea{background:rgba(255,255,255,0.04);border:1px solid var(--border);border-radius:10px;padding:13px 18px;color:var(--white);font-family:'Raleway',sans-serif;font-size:0.9rem;transition:all 0.3s;outline:none;width:100%;}
.form-group input:focus,.form-group select:focus,.form-group textarea:focus{border-color:var(--peacock-mid);background:rgba(0,95,115,0.08);box-shadow:0 0 0 3px rgba(0,163,150,0.15);}
.form-group select option{background:var(--card);color:var(--white);}
.form-group textarea{resize:vertical;min-height:100px;}
.form-submit{margin-top:20px;text-align:center;}

/* AUTH */
.auth-page{min-height:100vh;display:flex;align-items:center;justify-content:center;padding:100px 20px 60px;position:relative;}
.auth-bg{position:fixed;inset:0;background:radial-gradient(ellipse 60% 60% at 30% 40%,rgba(0,95,115,0.12) 0%,transparent 50%),radial-gradient(ellipse 50% 50% at 70% 60%,rgba(212,175,55,0.06) 0%,transparent 50%);z-index:0;pointer-events:none;}
.auth-card{background:var(--card);border:1px solid var(--border);border-radius:24px;padding:45px;width:100%;max-width:480px;position:relative;z-index:1;box-shadow:0 30px 80px rgba(0,0,0,0.5);animation:fadeInUp 0.8s ease forwards;opacity:0;}
.auth-logo{text-align:center;margin-bottom:25px;}
.auth-logo h2{font-family:'Cinzel Decorative',serif;font-size:1.5rem;color:var(--gold);margin-bottom:5px;}
.auth-logo p{color:var(--peacock-light);font-size:0.85rem;font-style:italic;}
.auth-tabs{display:flex;gap:5px;background:rgba(255,255,255,0.04);border-radius:12px;padding:5px;margin-bottom:25px;}
.auth-tab{flex:1;background:none;border:none;color:var(--gray);padding:10px;border-radius:8px;font-family:'Raleway',sans-serif;font-size:0.82rem;cursor:pointer;transition:all 0.3s;text-transform:uppercase;letter-spacing:1px;}
.auth-tab.active{background:rgba(212,175,55,0.15);color:var(--gold);}
.auth-form{display:none;}
.auth-form.active{display:block;}
.auth-footer{text-align:center;margin-top:20px;}
.auth-footer a{color:var(--peacock-light);text-decoration:none;font-size:0.85rem;}
.forgot-link{text-align:right;margin-bottom:15px;}
.forgot-link a{color:var(--gray);font-size:0.8rem;text-decoration:none;}
.forgot-link a:hover{color:var(--gold);}

/* DASHBOARD */
.dashboard-wrap{max-width:1100px;margin:0 auto;padding:40px 5%;}
.dash-header{margin-bottom:40px;padding:30px;background:var(--card);border:1px solid var(--border);border-radius:16px;display:flex;justify-content:space-between;align-items:center;flex-wrap:wrap;gap:15px;}
.dash-title{font-family:'Cinzel Decorative',serif;font-size:1.5rem;color:var(--gold);}
.dashboard-grid{display:grid;grid-template-columns:repeat(auto-fit,minmax(220px,1fr));gap:20px;margin-bottom:40px;}
.stat-card{background:var(--card);border:1px solid var(--border);border-radius:16px;padding:25px;text-align:center;}
.stat-num{font-family:'Cinzel Decorative',serif;font-size:2.5rem;color:var(--gold);}
.stat-label{font-size:0.78rem;letter-spacing:2px;text-transform:uppercase;color:var(--gray);}
.bookings-table-wrap{background:var(--card);border:1px solid var(--border);border-radius:16px;overflow:hidden;}
.bookings-table-wrap h3{font-family:'Cinzel Decorative',serif;color:var(--gold);padding:20px 25px;border-bottom:1px solid var(--border);}
.bookings-table{width:100%;border-collapse:collapse;}
.bookings-table th,.bookings-table td{padding:15px 25px;text-align:left;border-bottom:1px solid rgba(255,255,255,0.05);}
.bookings-table th{font-size:0.75rem;letter-spacing:2px;text-transform:uppercase;color:var(--gold-dark);}
.bookings-table td{font-size:0.88rem;color:rgba(245,245,240,0.75);}
.bookings-table tr:hover td{background:rgba(255,255,255,0.02);}
.status-badge{display:inline-block;padding:3px 12px;border-radius:20px;font-size:0.75rem;font-weight:600;letter-spacing:1px;text-transform:uppercase;}
.status-pending{background:rgba(212,175,55,0.15);color:var(--gold);}
.status-confirmed{background:rgba(46,204,113,0.15);color:var(--green);}
.status-cancelled{background:rgba(255,100,100,0.15);color:#ff6464;}

/* ADMIN */
.tab-nav{display:flex;gap:10px;margin-bottom:30px;border-bottom:1px solid var(--border);padding-bottom:0;flex-wrap:wrap;}
.tab-btn{background:none;border:none;color:var(--gray);padding:12px 25px;font-family:'Raleway',sans-serif;font-size:0.82rem;letter-spacing:1px;cursor:pointer;border-bottom:2px solid transparent;margin-bottom:-1px;transition:all 0.3s;text-transform:uppercase;}
.tab-btn.active{color:var(--gold);border-bottom-color:var(--gold);}
.tab-content{display:none;}
.tab-content.active{display:block;}

/* ALERT */
.alert{display:flex;align-items:center;gap:12px;padding:15px 20px;border-radius:12px;font-size:0.88rem;margin-bottom:20px;}
.alert-success{background:rgba(46,204,113,0.1);border:1px solid rgba(46,204,113,0.3);color:var(--green);}
.alert-error{background:rgba(255,100,100,0.1);border:1px solid rgba(255,100,100,0.3);color:#ff6464;}

/* FOOTER */
footer{background:rgba(0,0,0,0.6);border-top:1px solid var(--border);padding:60px 5% 30px;position:relative;z-index:1;}
.footer-grid{display:grid;grid-template-columns:2fr 1fr 1fr;gap:50px;margin-bottom:40px;}
.footer-brand h3{font-family:'Cinzel Decorative',serif;color:var(--gold);font-size:1.1rem;margin-bottom:15px;}
.footer-brand p{color:rgba(245,245,240,0.5);font-size:0.88rem;line-height:1.7;}
.footer-col h4{font-family:'Cinzel Decorative',serif;color:var(--gold);margin-bottom:15px;font-size:0.9rem;}
.footer-col ul{list-style:none;}
.footer-col ul li{margin-bottom:8px;}
.footer-col ul li a{color:rgba(245,245,240,0.5);text-decoration:none;font-size:0.85rem;transition:color 0.3s;}
