.social-links{display:flex;gap:12px;margin-top:20px;}
.social-links a{width:36px;height:36px;border-radius:50%;border:1px solid var(--border);display:flex;align-items:center;justify-content:center;color:var(--gray);text-decoration:none;transition:all 0.3s;font-size:0.85rem;}
.social-links a:hover{border-color:var(--gold);color:var(--gold);}
.footer-bottom{border-top:1px solid var(--border);padding-top:20px;display:flex;justify-content:space-between;align-items:center;flex-wrap:wrap;gap:10px;}
.footer-bottom p{color:rgba(245,245,240,0.4);font-size:0.8rem;}
.footer-bottom span{color:var(--gold);}

/* RESPONSIVE */
@media(max-width:768px){
    .nav-links{display:none;}
