    .dash-header{flex-direction:column;}
}

/* LOGO LIGHTBOX */
#logo-lightbox {
    position: fixed; inset: 0; background: rgba(0,0,0,0.92);
    z-index: 99999; display: none; align-items: center;
    justify-content: center; cursor: pointer;
    backdrop-filter: blur(8px);
    animation: fadeIn 0.3s ease;
}
#logo-lightbox.active { display: flex; }
#logo-lightbox img {
    max-width: 85vw; max-height: 85vh;
    object-fit: contain;
    filter: drop-shadow(0 0 40px rgba(212,175,55,0.6));
    animation: zoomIn 0.35s cubic-bezier(0.34,1.56,0.64,1);
    border-radius: 12px;
}
#logo-lightbox .lb-close {
    position: absolute; top: 20px; right: 25px;
    color: var(--gold); font-size: 2.2rem;
    cursor: pointer; opacity: 0.8; transition: opacity 0.2s;
    background: none; border: none; line-height: 1;
}
#logo-lightbox .lb-close:hover { opacity: 1; }
#logo-lightbox .lb-hint {
    position: absolute; bottom: 25px; left: 50%; transform: translateX(-50%);
    color: rgba(245,245,240,0.4); font-size: 0.8rem; letter-spacing: 2px;
    text-transform: uppercase;
}
@keyframes zoomIn { from { transform: scale(0.7); opacity: 0; } to { transform: scale(1); opacity: 1; } }
@keyframes fadeIn { from { opacity: 0; } to { opacity: 1; } }


