<script>
function filterProducts(cat, btn) {
    document.querySelectorAll('.product-filter-btn').forEach(b => {
        b.style.background = 'transparent';
        b.style.color = 'rgba(245,245,240,0.7)';
        b.style.borderColor = 'var(--border)';
    });
    btn.style.background = 'linear-gradient(135deg,var(--gold-dark),var(--gold))';
    btn.style.color = '#000';
    btn.style.borderColor = 'var(--gold)';
    document.querySelectorAll('.product-card').forEach(card => {
        if (cat === 'all' || card.dataset.category === cat) {
            card.style.display = '';
            card.style.opacity = '0';
            setTimeout(() => { card.style.transition = 'opacity 0.4s'; card.style.opacity = '1'; }, 50);
        } else {
            card.style.display = 'none';
        }
    });
}
</script>

