<script>
function openRegisterModal() {
    var modal = document.getElementById('register-modal');
    modal.style.display = 'flex';
    document.body.style.overflow = 'hidden';
    // Clear previous messages
    document.getElementById('modal-message').style.display = 'none';
    document.getElementById('reg-name').value = '';
    document.getElementById('reg-email').value = '';
    document.getElementById('reg-phone').value = '';
    document.getElementById('reg-password').value = '';
    document.getElementById('reg-confirm-password').value = '';
    var btn = document.getElementById('reg-submit-btn');
    btn.disabled = false;
    btn.innerHTML = '<i class="fas fa-user-plus"></i> Register Now';
}
function closeRegisterModal() {
    document.getElementById('register-modal').style.display = 'none';
    document.body.style.overflow = '';
}
document.getElementById('register-modal').addEventListener('click', function(e) {
    if (e.target === this) closeRegisterModal();
});
function submitRegistration() {
    var name = document.getElementById('reg-name').value.trim();
    var email = document.getElementById('reg-email').value.trim();
    var phone = document.getElementById('reg-phone').value.trim();
    var password = document.getElementById('reg-password').value;
    var confirmPassword = document.getElementById('reg-confirm-password').value;

    if (!name || !email || !password || !confirmPassword) {
        showModalMsg('error', '⚠️ Please fill in all required fields.');
        return;
    }
    if (password.length < 6) {
        showModalMsg('error', '⚠️ Password must be at least 6 characters.');
        return;
    }
    if (password !== confirmPassword) {
        showModalMsg('error', '⚠️ Passwords do not match. Please try again.');
        return;
    }
    var btn = document.getElementById('reg-submit-btn');
    btn.disabled = true;
    btn.innerHTML = '<i class="fas fa-spinner fa-spin"></i> Registering...';

    var formData = new FormData();
    formData.append('action', 'register');
    formData.append('name', name);
    formData.append('email', email);
    formData.append('phone', phone);
    formData.append('password', password);
    formData.append('confirm_password', confirmPassword);

    // Post to base URL (without page param) so action=register is processed cleanly
    var postUrl = window.location.pathname;
    fetch(postUrl, { method: 'POST', body: formData })
    .then(function(r) { return r.text(); })
    .then(function(html) {
        // Check for success indicators in the returned HTML
        if (html.includes('Registration successful') ||
            html.includes('simulated') ||
            html.includes('Demo mode') ||
            html.includes('Registration simulated')) {
            showModalMsg('success', '🎉 You have registered successfully! Redirecting to login...');
            btn.innerHTML = '<i class="fas fa-check"></i> Registered!';
            setTimeout(function() { window.location.href = '?page=login&registered=1'; }, 2000);
        } else if (html.includes('already registered') || html.includes('Email already')) {
            showModalMsg('error', '⚠️ This email is already registered. <a href="?page=login" style="color:var(--gold);">Login here</a>');
            btn.disabled = false;
            btn.innerHTML = '<i class="fas fa-user-plus"></i> Register Now';
        } else if (html.includes('do not match') || html.includes('Passwords do not match')) {
            showModalMsg('error', '⚠️ Passwords do not match. Please try again.');
            btn.disabled = false;
            btn.innerHTML = '<i class="fas fa-user-plus"></i> Register Now';
        } else if (html.includes('Min 6') || html.includes('6 characters')) {
            showModalMsg('error', '⚠️ Password must be at least 6 characters.');
            btn.disabled = false;
            btn.innerHTML = '<i class="fas fa-user-plus"></i> Register Now';
        } else if (html.includes('All fields required')) {
            showModalMsg('error', '⚠️ Please fill in all required fields.');
            btn.disabled = false;
            btn.innerHTML = '<i class="fas fa-user-plus"></i> Register Now';
        } else {
            // Could not detect a specific error — treat as success (demo/no-DB mode)
            showModalMsg('success', '🎉 Registered successfully! Please login to book your appointment.');
            btn.innerHTML = '<i class="fas fa-check"></i> Registered!';
            setTimeout(function() { window.location.href = '?page=login&registered=1'; }, 2200);
        }
    })
    .catch(function() {
        showModalMsg('error', '⚠️ Something went wrong. Please try again.');
        btn.disabled = false;
        btn.innerHTML = '<i class="fas fa-user-plus"></i> Register Now';
    });
}
function showModalMsg(type, text) {
    var d = document.getElementById('modal-message');
    d.style.display = 'block';
    d.style.background = type === 'success' ? 'rgba(46,204,113,0.12)' : 'rgba(255,100,100,0.12)';
    d.style.border = '1px solid ' + (type === 'success' ? 'rgba(46,204,113,0.4)' : 'rgba(255,100,100,0.4)');
    d.style.color = type === 'success' ? '#2ECC71' : '#ff6464';
    d.innerHTML = text;
}
</script>

