<script>
// PARTICLES
(function(){
    const canvas=document.getElementById('particles-canvas');
    const ctx=canvas.getContext('2d');
    let particles=[];let W,H;
    function resize(){W=canvas.width=window.innerWidth;H=canvas.height=window.innerHeight;}
    const COLORS=['#D4AF37','#005F73','#0A9396','#2ECC71','#F0D060','#94D2BD'];
    class Particle{
        constructor(){this.reset(true);}
        reset(init=false){this.x=Math.random()*W;this.y=init?Math.random()*H:H+10;this.r=Math.random()*2+0.3;this.color=COLORS[Math.floor(Math.random()*COLORS.length)];this.vy=-(Math.random()*0.6+0.2);this.vx=(Math.random()-0.5)*0.3;this.alpha=Math.random()*0.5+0.1;this.life=0;this.maxLife=Math.random()*200+100;}
        update(){this.x+=this.vx;this.y+=this.vy;this.life++;if(this.life>this.maxLife||this.y<-10)this.reset();}
        draw(){ctx.save();ctx.globalAlpha=this.alpha*(1-this.life/this.maxLife);ctx.fillStyle=this.color;ctx.beginPath();ctx.arc(this.x,this.y,this.r,0,Math.PI*2);ctx.fill();ctx.restore();}
    }
    function init(){resize();particles=Array.from({length:80},()=>new Particle());animate();}
    function animate(){ctx.clearRect(0,0,W,H);particles.forEach(p=>{p.update();p.draw();});requestAnimationFrame(animate);}
    window.addEventListener('resize',resize);
    window.addEventListener('load',init);
})();

// NAV SCROLL
window.addEventListener('scroll',()=>{
    const nav=document.getElementById('main-nav');
    if(nav){nav.style.padding=window.scrollY>50?'12px 5%':'18px 5%';nav.style.background=window.scrollY>50?'rgba(5,5,5,0.98)':'rgba(5,5,5,0.92)';}
});

// AUTH TAB
// Auto-open register tab if coming from booking page
if (window.location.search.includes('page=login') && document.referrer.includes('page=book')) {
    window.addEventListener('DOMContentLoaded', function() {
        var tabs = document.querySelectorAll('.auth-tab');
        if (tabs[2]) switchAuthTab(tabs[2], 'register-form');
    });
}
// Also handle direct register redirect from banner
document.addEventListener('DOMContentLoaded', function() {
    var params = new URLSearchParams(window.location.search);
    if (params.get('register') === '1') {
        var tabs = document.querySelectorAll('.auth-tab');
        if (tabs[2]) switchAuthTab(tabs[2], 'register-form');
    }
    // After successful registration from booking modal, stay on login tab and show success note
    if (params.get('registered') === '1') {
        var loginForm = document.getElementById('login-form');
        if (loginForm) {
            var banner = document.createElement('div');
            banner.style.cssText = 'background:rgba(46,204,113,0.12);border:1px solid rgba(46,204,113,0.4);color:#2ECC71;border-radius:10px;padding:12px 16px;margin-bottom:14px;font-size:0.88rem;text-align:center;';
            banner.innerHTML = '\uD83C\uDF89 Registration successful! Please login to book your appointment.';
            loginForm.insertBefore(banner, loginForm.firstChild);
            setTimeout(function(){ banner.style.transition='opacity 0.5s'; banner.style.opacity='0'; setTimeout(function(){ banner.remove(); }, 500); }, 5000);
        }
    }
});

function switchAuthTab(btn,formId){
    document.querySelectorAll('.auth-tab').forEach(t=>t.classList.remove('active'));
    document.querySelectorAll('.auth-form').forEach(f=>f.classList.remove('active'));
    btn.classList.add('active');
    document.getElementById(formId)?.classList.add('active');
}

// ADMIN TAB
function switchTab(btn,tabId){
    document.querySelectorAll('.tab-btn').forEach(t=>t.classList.remove('active'));
    document.querySelectorAll('.tab-content').forEach(c=>c.classList.remove('active'));
    btn.classList.add('active');
    document.getElementById(tabId)?.classList.add('active');
}

// SERVICE MODAL
function openModal(svc){
    document.getElementById('modalImg').src=svc.img;
    document.getElementById('modalImg').alt=svc.name;
    document.getElementById('modalIcon').textContent=svc.icon;
    document.getElementById('modalTitle').textContent=svc.name;
    document.getElementById('modalPrice').textContent=svc.price;
    document.getElementById('modalDesc').textContent=svc.details;
    document.getElementById('serviceModal').classList.add('active');
    document.body.style.overflow='hidden';
}
function closeModal(){
    document.getElementById('serviceModal').classList.remove('active');
    document.body.style.overflow='';
}
document.getElementById('serviceModal')?.addEventListener('click',function(e){if(e.target===this)closeModal();});
document.addEventListener('keydown',e=>{if(e.key==='Escape')closeModal();});

// GALLERY SWITCH
function switchGallery(panel,btn){
    document.querySelectorAll('.gallery-panel').forEach(p=>p.classList.remove('active'));
    document.querySelectorAll('.gallery-tab').forEach(t=>t.classList.remove('active'));
    document.getElementById('gallery-'+panel)?.classList.add('active');
    btn.classList.add('active');
}

// SCROLL REVEAL
const observer=new IntersectionObserver((entries)=>{
    entries.forEach(e=>{if(e.isIntersecting){e.target.classList.add('revealed');observer.unobserve(e.target);}});
},{threshold:0.1,rootMargin:'0px 0px -50px 0px'});
document.querySelectorAll('.scroll-reveal').forEach(el=>observer.observe(el));

// LOGO LIGHTBOX
function openLogo() {
    document.getElementById('logo-lightbox').classList.add('active');
    document.body.style.overflow = 'hidden';
}
function closeLogo() {
    document.getElementById('logo-lightbox').classList.remove('active');
    document.body.style.overflow = '';
}
document.addEventListener('keydown', e => { if(e.key === 'Escape') { closeLogo(); closeModal(); } });

// CLEAR LOGIN FIELDS
function clearLoginFields() {
    document.getElementById('login-email').value = '';
    document.getElementById('login-password').value = '';
    const hint = document.getElementById('login-autofill-hint');
    if(hint) { hint.style.opacity = '0'; hint.style.transition = 'opacity 0.4s'; setTimeout(() => hint.remove(), 400); }
}

// SMOOTH SCROLL
document.querySelectorAll('a[href^="#"]').forEach(a=>{
    a.addEventListener('click',e=>{
        const target=document.querySelector(a.getAttribute('href'));
        if(target){e.preventDefault();target.scrollIntoView({behavior:'smooth',block:'start'});}
    });
});

// AUTO DISMISS ALERT
setTimeout(()=>{
    document.querySelectorAll('.alert').forEach(a=>{
        a.style.transition='all 0.5s';a.style.opacity='0';
        setTimeout(()=>a.parentElement?.remove(),500);
    });
},4000);
</script>
</body>
</html>
